function buildGenreText(genreIds, mediaType) {
  if (!Array.isArray(genreIds) || genreIds.length === 0) {
    return mediaType === MEDIA_TYPES.TV ? '剧集' : '电影';
  }

  const genres = genreIds
    .map((genreId) => GLOBAL_GENRE_MAP[genreId])
    .filter(Boolean)
    .slice(0, 2);

  if (!genres.length) {
    return mediaType === MEDIA_TYPES.TV ? '剧集' : '电影';
  }

  return genres.join(' / ');
}

function getMinimumVoteCount(sortKey) {
  return sortKey === SORT_KEYS.RATING_ASC || sortKey === SORT_KEYS.RATING_DESC
    ? MIN_DISCOVER_VOTE_COUNT.rating
    : MIN_DISCOVER_VOTE_COUNT.default;
}

function getTmdbSortBy(mediaType, sortKey) {
  if (mediaType === MEDIA_TYPES.MOVIE) {
    switch (sortKey) {
      case SORT_KEYS.DATE_ASC:
        return 'primary_release_date.asc';
      case SORT_KEYS.DATE_DESC:
        return 'primary_release_date.desc';
      case SORT_KEYS.YEAR_ASC:
        return 'primary_release_date.asc';
      case SORT_KEYS.YEAR_DESC:
        return 'primary_release_date.desc';
      case SORT_KEYS.RATING_ASC:
        return 'vote_average.asc';
      case SORT_KEYS.RATING_DESC:
        return 'vote_average.desc';
      case SORT_KEYS.TITLE_DESC:
        return 'title.desc';
      case SORT_KEYS.TITLE_ASC:
      default:
        return 'title.asc';
    }
  }

  switch (sortKey) {
    case SORT_KEYS.DATE_ASC:
      return 'first_air_date.asc';
    case SORT_KEYS.DATE_DESC:
      return 'first_air_date.desc';
    case SORT_KEYS.YEAR_ASC:
      return 'first_air_date.asc';
    case SORT_KEYS.YEAR_DESC:
      return 'first_air_date.desc';
    case SORT_KEYS.RATING_ASC:
      return 'vote_average.asc';
    case SORT_KEYS.RATING_DESC:
      return 'vote_average.desc';
    case SORT_KEYS.TITLE_DESC:
      return 'name.desc';
    case SORT_KEYS.TITLE_ASC:
    default:
      return 'name.asc';
  }
}

function mergeLocalizedResults(mediaType, simplifiedResponse, traditionalResponse) {
  const mergedById = new Map();

  for (const item of traditionalResponse.results ?? []) {
    mergedById.set(item.id, {
      traditional: item,
    });
  }

  for (const item of simplifiedResponse.results ?? []) {
    const existing = mergedById.get(item.id) ?? {};
    existing.simplified = item;
    mergedById.set(item.id, existing);
  }

  const orderedIds = [
    ...(simplifiedResponse.results ?? []).map((item) => item.id),
    ...(traditionalResponse.results ?? []).map((item) => item.id),
  ];

  const dedupedIds = Array.from(new Set(orderedIds));
  const records = dedupedIds
    .map((id) => {
      const localized = mergedById.get(id);
      const baseItem = localized?.simplified ?? localized?.traditional;

      if (!baseItem) {
        return null;
      }

      const simplifiedTitle = getRawTitle(localized.simplified, mediaType);
      const traditionalTitle = getRawTitle(localized.traditional, mediaType);
      const originalTitle = getRawOriginalTitle(baseItem, mediaType);
      const displayTitle = resolveDisplayTitle({
        simplifiedTitle,
        traditionalTitle,
        originalTitle,
      });

      return {
        tmdbId: id,
        mediaType,
        displayTitle,
        simplifiedTitle: normalizeTitle(simplifiedTitle),
        traditionalTitle: normalizeTitle(traditionalTitle),
        originalTitle: normalizeTitle(originalTitle),
        overview: chooseLocalizedField(localized.simplified, localized.traditional, (item) => item?.overview),
        genreIds: Array.isArray(baseItem.genre_ids) ? baseItem.genre_ids : [],
        originalLanguage: baseItem.original_language ?? '',
        originCountry: Array.isArray(baseItem.origin_country) ? baseItem.origin_country : [],
        releaseDate: getRawDate(baseItem, mediaType) ?? '',
        adult: getRawAdultFlag(baseItem),
        voteCount: Number.isFinite(baseItem.vote_count) ? baseItem.vote_count : 0,
        voteAverage: Number.isFinite(baseItem.vote_average) ? baseItem.vote_average : NaN,
        posterPath: buildImageUrl('w500', baseItem.poster_path),
        backdropPath: buildImageUrl('w780', baseItem.backdrop_path),
      };
    })
    .filter(Boolean);

  return {
    results: records,
    totalPages: Math.max(simplifiedResponse.total_pages ?? 0, traditionalResponse.total_pages ?? 0),
  };
}

function createCacheState(storage, maxBytes) {
  return {
    storage,
    maxBytes,
    manifest: null,
    queue: Promise.resolve(),
  };
}

async function withCacheLock(cacheState, operation) {
  const previous = cacheState.queue;
  let releaseLock = () => {};

  cacheState.queue = new Promise((resolve) => {
    releaseLock = resolve;
  });

  await previous;

  try {
    return await operation();
  } finally {
    releaseLock();
  }
}

async function loadCacheManifest(cacheState) {
  if (cacheState.manifest) {
    return cacheState.manifest;
  }

  const rawManifest = await cacheState.storage.get(CACHE_MANIFEST_KEY);
  const parsed = rawManifest ? parseJsonSafely(rawManifest) : null;

  if (parsed && parsed.entries && typeof parsed.entries === 'object') {
    cacheState.manifest = parsed;
    return parsed;
  }

  cacheState.manifest = {
    entries: {},
  };

  return cacheState.manifest;
}

async function saveCacheManifest(cacheState, manifest) {
  cacheState.manifest = manifest;
  await cacheState.storage.set(CACHE_MANIFEST_KEY, JSON.stringify(manifest));
}

function getManifestTotalBytes(manifest) {
  return Object.values(manifest.entries).reduce(
    (sum, entry) => sum + (Number.isFinite(entry?.size) ? entry.size : 0),
    0,
  );
}

async function pruneCache(cacheState, manifest, maxBytes) {
  const now = Date.now();
  const expiredKeys = Object.entries(manifest.entries)
    .filter(([, entry]) => !entry || !Number.isFinite(entry.expiresAt) || entry.expiresAt <= now)
    .map(([key]) => key);

  for (const key of expiredKeys) {
    delete manifest.entries[key];
    await cacheState.storage.remove(key).catch(() => {});
  }

  let totalBytes = getManifestTotalBytes(manifest);
  if (totalBytes <= maxBytes) {
    return;
  }

  const keysByLastAccess = Object.entries(manifest.entries)
    .sort(([, left], [, right]) => (left.lastAccess ?? 0) - (right.lastAccess ?? 0))
    .map(([key]) => key);

  for (const key of keysByLastAccess) {
    const entry = manifest.entries[key];
    delete manifest.entries[key];
    totalBytes -= Number.isFinite(entry?.size) ? entry.size : 0;
    await cacheState.storage.remove(key).catch(() => {});

    if (totalBytes <= maxBytes) {
      break;
    }
  }
}

async function getCachedJsonValue(cacheState, cacheKey) {
  return withCacheLock(cacheState, async () => {
    const manifest = await loadCacheManifest(cacheState);
    const entry = manifest.entries[cacheKey];

    if (!entry) {
      return null;
    }

    const now = Date.now();
    if (!Number.isFinite(entry.expiresAt) || entry.expiresAt <= now) {
      delete manifest.entries[cacheKey];
      await cacheState.storage.remove(cacheKey).catch(() => {});
      await saveCacheManifest(cacheState, manifest);
      return null;
    }

    const rawValue = await cacheState.storage.get(cacheKey);
    if (!isMeaningfulText(rawValue)) {
      delete manifest.entries[cacheKey];
      await saveCacheManifest(cacheState, manifest);
      return null;
    }

    entry.lastAccess = now;
    await saveCacheManifest(cacheState, manifest);
    return parseJsonSafely(rawValue);
  });
}

async function setCachedJsonValue(cacheState, cacheKey, value, { namespace, ttlSeconds, maxBytes }) {
  return withCacheLock(cacheState, async () => {
    const rawValue = JSON.stringify(value);
    const size = estimateStringBytes(cacheKey) + estimateStringBytes(rawValue);

    if (size > maxBytes) {
      return;
    }

    const manifest = await loadCacheManifest(cacheState);
    const now = Date.now();

    if (manifest.entries[cacheKey]) {
      delete manifest.entries[cacheKey];
      await cacheState.storage.remove(cacheKey).catch(() => {});
    }

    manifest.entries[cacheKey] = {
      namespace,
      size,
      lastAccess: now,
      expiresAt: now + ttlSeconds * 1000,
    };

    await pruneCache(cacheState, manifest, Math.max(maxBytes - size, 0));
    await cacheState.storage.set(cacheKey, rawValue);
    await saveCacheManifest(cacheState, manifest);
  });
}

async function cachedTmdbGet(path, options, runtime) {
  const cacheKey = buildCacheStorageKey(CACHE_NAMESPACE_TMDB, {
    path,
    params: Object.fromEntries(
      Object.entries(options?.params ?? {}).sort(([leftKey], [rightKey]) => leftKey.localeCompare(rightKey)),
    ),
  });

  const cachedValue = await getCachedJsonValue(runtime.cacheState, cacheKey);
  if (cachedValue) {
    return cachedValue;
  }

  const response = await runtime.tmdbGet(path, options);

  await setCachedJsonValue(runtime.cacheState, cacheKey, response, {
    namespace: CACHE_NAMESPACE_TMDB,
    ttlSeconds: TMDB_CACHE_TTL_SECONDS,
    maxBytes: runtime.cacheMaxBytes,
  }).catch(() => {});

  return response;
}

async function requestTranslationBatch(titles, translationConfig, runtime) {
  if (isTranslationProxyMode(translationConfig)) {
    const response = await runtime.httpPost(
      normalizeUrl(translationConfig.baseUrl),
      {
        titles,
        model: translationConfig.model,
      },
      {
        headers: {
          'Content-Type': 'application/json',
        },
      },
    );

    if (Array.isArray(response?.translations)) {
      return response.translations.map((value) => normalizeTitle(String(value)));
    }

    throw new Error('翻译代理返回格式异常');
  }

  const requestBody = {
    model: translationConfig.model,
    temperature: 0.1,
    max_tokens: 160,
    response_format: {
      type: 'json_object',
    },
    messages: [
      {
        role: 'system',
        content:
          '你是影视标题翻译器。请只把输入标题翻译成简体中文片名/剧名。不要解释，不要扩写，不要保留编号。只输出 JSON，对象中只能包含 translations 数组。',
      },
      {
        role: 'user',
        content: JSON.stringify({ translations: titles }),
      },
    ],
  };

  if (modelSupportsThinkingToggle(translationConfig.model)) {
    requestBody.enable_thinking = false;
  }

  const response = await runtime.httpPost(
    buildOpenAiChatCompletionsUrl(translationConfig.baseUrl),
    requestBody,
    {
      headers: {
        Authorization: `Bearer ${translationConfig.token}`,
      },
      timeoutMs: TRANSLATION_HTTP_TIMEOUT_MS,
    },
  );

  const content = response?.choices?.[0]?.message?.content ?? '';
  const parsedTranslations = parseTranslationResponseContent(content, titles.length);

  return titles.map((title, index) => normalizeTitle(parsedTranslations[index]) || title);
}

async function translateTitlesWithCache(titles, translationConfig, runtime) {
  if (!hasTranslationConfig(translationConfig) || !titles.length) {
    return new Map();
  }

  const uniqueTitles = Array.from(new Set(titles.map((title) => normalizeTitle(title)).filter(Boolean)));
  const translatedMap = new Map();
  const missingTitles = [];

  for (const title of uniqueTitles) {
    const cacheKey = buildCacheStorageKey(CACHE_NAMESPACE_TRANSLATE, {
      baseUrl: translationConfig.baseUrl,
      model: translationConfig.model,
      promptVersion: TRANSLATION_PROMPT_VERSION,
      title,
    });
    const cachedValue = await getCachedJsonValue(runtime.cacheState, cacheKey);

    if (cachedValue?.translatedTitle) {
      translatedMap.set(title, normalizeTitle(cachedValue.translatedTitle));
      continue;
    }

    missingTitles.push(title);
  }

  for (let index = 0; index < missingTitles.length; index += TRANSLATION_BATCH_SIZE) {
    const batch = missingTitles.slice(index, index + TRANSLATION_BATCH_SIZE);
    let translatedBatch = batch;

    try {
      translatedBatch = await requestTranslationBatch(batch, translationConfig, runtime);
    } catch {
      translatedBatch = batch;
    }

    for (const [batchIndex, title] of batch.entries()) {
      const translatedTitle = normalizeTitle(translatedBatch[batchIndex]) || title;
      translatedMap.set(title, translatedTitle);

      const cacheKey = buildCacheStorageKey(CACHE_NAMESPACE_TRANSLATE, {
        baseUrl: translationConfig.baseUrl,
        model: translationConfig.model,
        promptVersion: TRANSLATION_PROMPT_VERSION,
        title,
      });

      await setCachedJsonValue(runtime.cacheState, cacheKey, { translatedTitle }, {
        namespace: CACHE_NAMESPACE_TRANSLATE,
        ttlSeconds: TRANSLATION_CACHE_TTL_SECONDS,
        maxBytes: runtime.cacheMaxBytes,
      }).catch(() => {});
    }
  }

  return translatedMap;
}

async function applyMachineTranslationFallback(records, translationConfig, runtime) {
  const translationTargets = records.filter((record) => shouldAttemptMachineTranslation(record));

  if (!translationTargets.length) {
    return records;
  }

  const translatedMap = await translateTitlesWithCache(
    translationTargets.map((record) => record.originalTitle),
    translationConfig,
    runtime,
  );

  for (const record of translationTargets) {
    const translatedTitle = translatedMap.get(record.originalTitle);

    if (isMeaningfulText(translatedTitle)) {
      record.displayTitle = translatedTitle;
    }
  }

  return records;
}

function buildDiscoverParams(mediaType, rule, sortKey, sourcePage, todayDate) {
  const params = {
    include_adult: false,
    page: sourcePage,
    sort_by: getTmdbSortBy(mediaType, sortKey),
    'vote_count.gte': getMinimumVoteCount(sortKey),
    'vote_average.gte': 0.1,
    ...buildRuleDiscoverParams(rule),
  };

  if (mediaType === MEDIA_TYPES.MOVIE) {
    params.include_video = false;
    params['primary_release_date.lte'] = todayDate;
  } else {
    params['first_air_date.lte'] = todayDate;
  }

  return stringifyParams(params);
}

function createRuntime(rawParams, overrides = {}) {
  const storage = overrides.storage ?? getDefaultStorage();
  const cacheMaxBytes = overrides.cacheOptions?.maxBytes ?? CACHE_MAX_BYTES;

  return {
    tmdbGet: overrides.tmdbGet ?? getDefaultTmdbGet(),
    httpPost: overrides.httpPost ?? getDefaultHttpPost(),
    storage,
    cacheMaxBytes,
    cacheState: createCacheState(storage, cacheMaxBytes),
    translationConfig: normalizeTranslationConfig(rawParams),
  };
}

async function fetchLocalizedPage({ mediaType, rule, sortKey, sourcePage, runtime, todayDate }) {
  const endpoint = mediaType === MEDIA_TYPES.MOVIE ? 'discover/movie' : 'discover/tv';
  const commonParams = buildDiscoverParams(mediaType, rule, sortKey, sourcePage, todayDate);

  const [simplifiedResponse, traditionalResponse] = await Promise.all([
    cachedTmdbGet(endpoint, {
      params: {
        ...commonParams,
        language: TMDB_LANGUAGE_SIMPLIFIED,
      },
    }, runtime),
    cachedTmdbGet(endpoint, {
      params: {
        ...commonParams,
        language: TMDB_LANGUAGE_TRADITIONAL,
      },
    }, runtime),
  ]);

  return mergeLocalizedResults(mediaType, simplifiedResponse ?? {}, traditionalResponse ?? {});
}

const EXPLICIT_ADULT_PATTERNS = [
  /\b(?:porn|pornographic|hardcore|xxx)\b/i,
  /(?:成人影片|成人视频|成人電影|黃色電影|黄片|黃片|无码|無碼|AV片|成人向)/i,
];

function containsExplicitAdultText(record) {
  const searchableText = [
    record.displayTitle,
    record.simplifiedTitle,
    record.traditionalTitle,
    record.originalTitle,
    record.overview,
  ]
    .map((value) => normalizeTitle(value))
    .filter(Boolean)
    .join('\n');

  return EXPLICIT_ADULT_PATTERNS.some((pattern) => pattern.test(searchableText));
}

function isRecordReleased(record, todayDate) {
  if (!isMeaningfulText(record.releaseDate)) {
    return true;
  }

  return record.releaseDate <= todayDate;
}

function isAllowedRecord(record, todayDate, sortKey) {
  if (!isRecordReleased(record, todayDate)) {
    return false;
  }

  if (!Number.isFinite(record.voteAverage) || record.voteAverage <= 0) {
    return false;
  }

  if (!Number.isFinite(record.voteCount) || record.voteCount < getMinimumVoteCount(sortKey)) {
    return false;
  }

  if (record.adult === true) {
    return false;
  }

  if (containsExplicitAdultText(record)) {
    return false;
  }

  return true;
}

function getProgressiveFetchPlan(params) {
  const neededItemCount = params.page * params.count;

  return {
    sourceStartPage: 1,
    sourceEndPage: MAX_PROGRESSIVE_SOURCE_PAGES,
    neededCollectedCount: neededItemCount,
  };
}

function classifyMediaRecord(mediaType, record) {
  const rules = getRules(mediaType);

  for (const rule of rules) {
    if (rule.catchAll || matchesRule(record, rule)) {
      return rule;
    }
  }

  return null;
}

function compareText(left, right) {
  return left.localeCompare(right, 'zh-Hans-CN', {
    numeric: true,
    sensitivity: 'base',
  });
}

function compareOptionalDate(left, right) {
  const leftDate = Date.parse(left || '');
  const rightDate = Date.parse(right || '');

  if (Number.isNaN(leftDate) && Number.isNaN(rightDate)) {
    return 0;
  }

  if (Number.isNaN(leftDate)) {
    return 1;
  }

  if (Number.isNaN(rightDate)) {
    return -1;
  }

  return leftDate - rightDate;
}

function compareOptionalNumber(left, right) {
  const safeLeft = Number.isFinite(left) ? left : -Infinity;
  const safeRight = Number.isFinite(right) ? right : -Infinity;

  if (safeLeft === safeRight) {
    return 0;
  }

  return safeLeft - safeRight;
}

function extractYear(dateText) {
  if (!isMeaningfulText(dateText)) {
    return -Infinity;
  }

  const year = Number.parseInt(dateText.slice(0, 4), 10);
  return Number.isFinite(year) ? year : -Infinity;
}

function sortCatalogRecords(records, sortKey) {
  const sorted = [...records];

  sorted.sort((left, right) => {
    switch (sortKey) {
      case SORT_KEYS.DATE_ASC:
        return (
          compareOptionalDate(left.releaseDate, right.releaseDate) ||
          compareText(left.displayTitle, right.displayTitle) ||
          left.tmdbId - right.tmdbId
        );
      case SORT_KEYS.DATE_DESC:
        return (
          compareOptionalDate(right.releaseDate, left.releaseDate) ||
          compareText(left.displayTitle, right.displayTitle) ||
          left.tmdbId - right.tmdbId
        );
      case SORT_KEYS.YEAR_ASC:
        return (
          extractYear(left.releaseDate) - extractYear(right.releaseDate) ||
          compareOptionalDate(left.releaseDate, right.releaseDate) ||
          compareText(left.displayTitle, right.displayTitle) ||
          left.tmdbId - right.tmdbId
        );
      case SORT_KEYS.YEAR_DESC:
        return (
          extractYear(right.releaseDate) - extractYear(left.releaseDate) ||
          compareOptionalDate(right.releaseDate, left.releaseDate) ||
          compareText(left.displayTitle, right.displayTitle) ||
          left.tmdbId - right.tmdbId
        );
      case SORT_KEYS.RATING_ASC:
        return (
          compareOptionalNumber(left.voteAverage, right.voteAverage) ||
          compareOptionalDate(right.releaseDate, left.releaseDate) ||
          compareText(left.displayTitle, right.displayTitle) ||
          left.tmdbId - right.tmdbId
        );
      case SORT_KEYS.RATING_DESC:
        return (
          compareOptionalNumber(right.voteAverage, left.voteAverage) ||
          compareOptionalDate(right.releaseDate, left.releaseDate) ||
          compareText(left.displayTitle, right.displayTitle) ||
          left.tmdbId - right.tmdbId
        );
      case SORT_KEYS.TITLE_DESC:
        return (
          compareText(right.displayTitle, left.displayTitle) ||
          compareOptionalDate(right.releaseDate, left.releaseDate) ||
          left.tmdbId - right.tmdbId
        );
      case SORT_KEYS.TITLE_ASC:
      default:
        return (
          compareText(left.displayTitle, right.displayTitle) ||
          compareOptionalDate(right.releaseDate, left.releaseDate) ||
          left.tmdbId - right.tmdbId
        );
    }
  });

  return sorted;
}

function mapRecordToVideoItem(record, categoryTitle) {
  const detailText = [record.releaseDate, categoryTitle].filter(Boolean).join(' · ');

  return {
    id: String(record.tmdbId),
    tmdbId: record.tmdbId,
    type: 'tmdb',
    title: record.displayTitle || record.originalTitle || `${record.mediaType}-${record.tmdbId}`,
    posterPath: record.posterPath,
    backdropPath: record.backdropPath,
    releaseDate: record.releaseDate || undefined,
    mediaType: record.mediaType,
    genreTitle: buildGenreText(record.genreIds, record.mediaType),
    description: detailText
      ? `${detailText}\n${record.overview || '暂无简介'}`
      : record.overview || '暂无简介',
  };
}

function getLegacyCategoryValue(params = {}) {
  const legacyMediaType =
    params.mediaType === MEDIA_TYPES.TV ? MEDIA_TYPES.TV : MEDIA_TYPES.MOVIE;

  return legacyMediaType === MEDIA_TYPES.TV ? params.tvCategory : params.movieCategory;
}

function normalizeBrowseParams(params = {}) {
  const sortValue =
    params.sort_by ??
    params.movieSort ??
    params.tvSort;

  const categoryId = pickValidValue(
    params.category ?? getLegacyCategoryValue(params),
    getCategoryOptions(),
    getDefaultCategory(),
  );
  const sortKey = pickValidValue(sortValue, getSortOptions(), getDefaultSort());
  const count = coerceInteger(params.count, DEFAULT_COUNT, { min: 1, max: MAX_COUNT });
  const page = coerceInteger(params.page, DEFAULT_PAGE, { min: 1 });

  return {
    categoryId,
    sortKey,
    count,
    page,
  };
}

async function browseCatalog(rawParams = {}, overrides = {}) {
  const params = normalizeBrowseParams(rawParams);
  const runtime = createRuntime(rawParams, overrides);
  const todayDate = getTodayDateString();
  const sourceMediaTypes = getCategoryMediaTypes(params.categoryId);
  const selectedScopes = sourceMediaTypes
    .map((mediaType) => ({
      mediaType,
      rule: getRuleById(mediaType, params.categoryId),
      nextPage: 1,
      totalPages: 0,
      exhausted: false,
    }))
    .filter((scope) => scope.rule);

  if (!selectedScopes.length) {
    throw new Error(`未知分类：${params.categoryId}`);
  }

  const fetchPlan = getProgressiveFetchPlan(params);
  const collected = [];
  const seenRecordKeys = new Set();

  // 统一按“轮次”并行抓取所有相关媒体源。
  // 这样纪录片、演唱会这类跨 movie/tv 的大类可以在同一个排序集合里先合并、再分页。
  while (selectedScopes.some((scope) => !scope.exhausted)) {
    const activeScopes = selectedScopes.filter((scope) => !scope.exhausted);
    const pageResults = await Promise.all(
      activeScopes.map((scope) =>
        fetchLocalizedPage({
          mediaType: scope.mediaType,
          rule: scope.rule,
          sortKey: params.sortKey,
          sourcePage: scope.nextPage,
          runtime,
          todayDate,
        }),
      ),
    );

    for (const [index, scope] of activeScopes.entries()) {
      const { results, totalPages } = pageResults[index];
      scope.totalPages = totalPages;

      for (const record of results) {
        if (!isAllowedRecord(record, todayDate, params.sortKey)) {
          continue;
        }

        const matchedRule = classifyMediaRecord(scope.mediaType, record);

        if (!matchedRule || matchedRule.id !== scope.rule.id) {
          continue;
        }

        // 合并 movie/tv 大类时，TMDb 数字 id 可能跨媒体类型重复，必须把媒体类型一起算入去重键。
        const recordKey = `${record.mediaType}:${record.tmdbId}`;
        if (seenRecordKeys.has(recordKey)) {
          continue;
        }

        seenRecordKeys.add(recordKey);
        collected.push(record);
      }

      const reachedConfiguredLimit = scope.nextPage >= MAX_PROGRESSIVE_SOURCE_PAGES;
      const reachedRemoteEnd = !results.length || (totalPages > 0 && scope.nextPage >= totalPages);

      if (reachedConfiguredLimit || reachedRemoteEnd) {
        scope.exhausted = true;
        continue;
      }

      scope.nextPage += 1;
    }

    if (collected.length >= fetchPlan.neededCollectedCount) {
      break;
    }
  }

  if (params.sortKey === SORT_KEYS.TITLE_ASC || params.sortKey === SORT_KEYS.TITLE_DESC) {
    await applyMachineTranslationFallback(collected, runtime.translationConfig, runtime);
  }

  const sorted = sortCatalogRecords(collected, params.sortKey);
  const startIndex = (params.page - 1) * params.count;
  const endIndex = startIndex + params.count;
  const categoryTitle = selectedScopes[0].rule.title;
  const pagedRecords = sorted.slice(startIndex, endIndex);

  if (params.sortKey !== SORT_KEYS.TITLE_ASC && params.sortKey !== SORT_KEYS.TITLE_DESC) {
    await applyMachineTranslationFallback(pagedRecords, runtime.translationConfig, runtime);
  }

  return pagedRecords.map((record) => mapRecordToVideoItem(record, categoryTitle));
}

